def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 5:
            priority = (ratio ** 5) + np.sin(capacity) * 10
            for x in range(1, int(capacity) + 3):
                if x % 3 == 0:
                    priority += np.tanh(ratio / (x + epsilon))
                elif x % 2 == 0:
                    priority -= np.exp(-ratio * x)
                else:
                    priority += np.log1p(capacity * x) / (x + epsilon)
            if capacity % 4 == 0:
                priority *= 1.3
            else:
                priority /= 1.2
        elif 3 < ratio <= 5:
            priority = (np.sqrt(ratio) * np.log1p(capacity)) ** 2
            for y in range(1, int(item) + int(capacity) + 1):
                if y % 5 == 0:
                    priority += (y ** 1.5) / (capacity + 1)
                elif y % 2 == 1:
                    priority -= np.cos(y / (item + epsilon))
                else:
                    priority += np.sin(y) / (y + epsilon)
            priority = max(priority, 0)
        elif 1 <= ratio <= 3:
            priority = np.log1p(ratio * capacity) / (capacity + epsilon)
            product = 1
            for z in range(1, int(capacity // 2) + 1):
                val = (ratio ** z) * ((capacity + 1) / (z + epsilon))
                product *= (np.tanh(val) + 1.1)
                if product > 10:
                    break
            priority *= product
        elif 0.1 < ratio < 1:
            priority = 0
            for w in range(1, int(capacity) + 1):
                if w % 4 == 0:
                    priority += np.sqrt(ratio * w) / (w + epsilon)
                else:
                    priority -= (ratio ** w) / (w * (capacity + 1) + epsilon)
            priority = abs(priority) + np.log1p(capacity)
        else:
            total_sum = 0
            alternating = 1
            for v in range(1, int(capacity * 2) + 1):
                val = (item ** v) / (v ** 2 + epsilon)
                total_sum += alternating * val
                alternating *= -1
            priority = np.abs(total_sum) + 0.7 * ratio
        if capacity < item:
            diff = item - capacity
            penalty = diff ** 2 * 20
            for p in range(1, int(diff * 2) + 1):
                if p % 7 == 0:
                    penalty += np.power(np.log(p + epsilon + 1), 1.5)
                elif p % 3 == 0:
                    penalty -= p * 0.05
                else:
                    penalty += np.sqrt(p)
            penalty = max(penalty, 1)
            priority += penalty ** 0.8
        priorities[i] = priority
    return priorities
